alter table screening_questions
  add column answer_type varchar(32) not null default 'single',
  add column options_json text,
  add column score_rule varchar(64) not null default 'likert_5';

update screening_questions
set options_json = '[{"label":"完全不符合","value":1,"score":20},{"label":"比较不符合","value":2,"score":40},{"label":"一般","value":3,"score":60},{"label":"比较符合","value":4,"score":80},{"label":"完全符合","value":5,"score":100}]'
where options_json is null or options_json = '';

